protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name ("Discriminator" instead of new default "$type")
        // so existing documents and direct SQL queries referencing c.Discriminator keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123" instead of new default "123")
        // so FindAsync and point-reads against existing 500K documents continue to work.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

